import React, { useRef, useEffect, useState } from 'react';
import { useWebRTC } from '../../hooks/useWebRTC';

interface BroadcasterViewProps {
  roomId: string;
  userId: string;
  onLeave: () => void;
}

export const BroadcasterView: React.FC<BroadcasterViewProps> = ({ roomId, userId, onLeave }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isBroadcasting, setIsBroadcasting] = useState(false);

  const { localStream, isConnected, error, startBroadcast, stopBroadcast, leave } = useWebRTC({
    roomId,
    role: 'broadcaster',
    userId,
  });

  useEffect(() => {
    if (localStream && videoRef.current) {
      videoRef.current.srcObject = localStream;
    }
  }, [localStream]);

  const handleStartBroadcast = async () => {
    try {
      await startBroadcast();
      setIsBroadcasting(true);
    } catch (err) {
      console.error('Failed to start broadcast:', err);
    }
  };

  const handleStopBroadcast = () => {
    stopBroadcast();
    setIsBroadcasting(false);
  };

  const handleLeave = () => {
    stopBroadcast();
    leave();
    onLeave();
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h2>Broadcasting</h2>
        <div style={styles.status}>
          {isConnected ? (
            <span style={styles.statusConnected}>● Connected</span>
          ) : (
            <span style={styles.statusDisconnected}>● Disconnected</span>
          )}
        </div>
      </div>

      <div style={styles.videoContainer}>
        <video
          ref={videoRef}
          autoPlay
          muted
          playsInline
          style={styles.video}
        />

        {!isBroadcasting && (
          <div style={styles.overlay}>
            <p>Click "Start Broadcast" to begin streaming</p>
          </div>
        )}
      </div>

      {error && <div style={styles.error}>{error}</div>}

      <div style={styles.controls}>
        {!isBroadcasting ? (
          <button onClick={handleStartBroadcast} style={styles.startButton}>
            Start Broadcast
          </button>
        ) : (
          <button onClick={handleStopBroadcast} style={styles.stopButton}>
            Stop Broadcast
          </button>
        )}

        <button onClick={handleLeave} style={styles.leaveButton}>
          Leave Room
        </button>
      </div>

      <div style={styles.info}>
        <p><strong>Room ID:</strong> {roomId}</p>
        <p><strong>User ID:</strong> {userId}</p>
        <p><strong>Role:</strong> Broadcaster</p>
      </div>
    </div>
  );
};

const styles: { [key: string]: React.CSSProperties } = {
  container: {
    padding: '20px',
    maxWidth: '1000px',
    margin: '0 auto',
  },
  header: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '20px',
  },
  status: {
    fontSize: '14px',
  },
  statusConnected: {
    color: 'green',
  },
  statusDisconnected: {
    color: 'red',
  },
  videoContainer: {
    position: 'relative',
    backgroundColor: '#000',
    borderRadius: '8px',
    overflow: 'hidden',
    marginBottom: '20px',
  },
  video: {
    width: '100%',
    height: 'auto',
    display: 'block',
  },
  overlay: {
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    backgroundColor: 'rgba(0, 0, 0, 0.7)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    color: 'white',
    fontSize: '18px',
  },
  controls: {
    display: 'flex',
    gap: '10px',
    marginBottom: '20px',
  },
  startButton: {
    flex: 1,
    padding: '15px',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    backgroundColor: '#28a745',
    color: 'white',
    fontSize: '16px',
    fontWeight: 'bold',
  },
  stopButton: {
    flex: 1,
    padding: '15px',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    backgroundColor: '#dc3545',
    color: 'white',
    fontSize: '16px',
    fontWeight: 'bold',
  },
  leaveButton: {
    flex: 1,
    padding: '15px',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    backgroundColor: '#6c757d',
    color: 'white',
    fontSize: '16px',
    fontWeight: 'bold',
  },
  info: {
    padding: '15px',
    backgroundColor: '#f8f9fa',
    borderRadius: '4px',
  },
  error: {
    color: 'red',
    padding: '10px',
    marginBottom: '10px',
    backgroundColor: '#fee',
    borderRadius: '4px',
  },
};
